import{_ as d,o as a,c as t,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Find: búsqueda rápida de archivos | Dotfiles (ES)","titleTemplate":":title","description":"Agiliza la búsqueda con alias basados en fd. Salida colorida y comandos intuitivos. Compatible con macOS, Linux y WSL a través de Dotfiles.","frontmatter":{"title":"Alias Find: búsqueda rápida de archivos","description":"Agiliza la búsqueda con alias basados en fd. Salida colorida y comandos intuitivos. Compatible con macOS, Linux y WSL a través de Dotfiles.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Find: búsqueda rápida de archivos preview","canonical":"/es/aliases/find/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Find: búsqueda rápida de archivos","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Find | Dotfiles","permalink":"/es/aliases/find/","sidebar":true,"meta":[{"name":"keywords","content":"alias find, comando fd, búsqueda de archivos, alias shell, dotfiles, find unix"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Find | Dotfiles"},{"name":"twitter:description","content":"Agiliza la búsqueda con alias basados en fd. Salida colorida y comandos intuitivos."},{"name":"og:title","content":"Alias Find | Dotfiles"},{"name":"og:description","content":"Agiliza la búsqueda con alias basados en fd. Salida colorida y comandos intuitivos."},{"name":"og:image:alt","content":"Dotfiles - Diseñado para tu vida en el shell"},{"name":"og:locale","content":"es_ES"}]},"headers":[],"relativePath":"es/aliases/find/index.md","filePath":"es/aliases/find/index.md","lastUpdated":1773010926000}'),i={name:"es/aliases/find/index.md"};function s(r,e,n,c,l,f){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="alias-find" tabindex="-1">Alias Find <a class="header-anchor" href="#alias-find" aria-label="Permalink to &quot;Alias Find&quot;">​</a></h1><p>Atajos potentes para buscar archivos con fd, la alternativa moderna a find.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Estos alias ofrecen una interfaz simplificada para <code>fd</code>, una alternativa rápida y amigable a <code>find</code>. Definidos en <code>find.aliases.sh</code>, se cargan automáticamente por chezmoi y ofrecen salida colorida, sintaxis intuitiva y comandos memorables para búsquedas comunes.</p><p>Cuando <code>fd</code> está disponible, la orden <code>find</code> se aliasa automáticamente para usar <code>fd</code>, ofreciendo mejor rendimiento y una sintaxis más simple por defecto.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="comandos-principales" tabindex="-1">Comandos principales <a class="header-anchor" href="#comandos-principales" aria-label="Permalink to &quot;Comandos principales&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>fd</code></td><td><code>fd --color always</code></td><td>Buscar archivos con salida colorida</td></tr><tr><td><code>find</code></td><td><code>fd</code></td><td>Usar fd como reemplazo de find</td></tr></tbody></table><h3 id="opciones-de-busqueda" tabindex="-1">Opciones de búsqueda <a class="header-anchor" href="#opciones-de-busqueda" aria-label="Permalink to &quot;Opciones de búsqueda&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>fda</code></td><td><code>fd --absolute-path</code></td><td>Mostrar resultados con rutas absolutas</td></tr><tr><td><code>fdc</code></td><td><code>fd --ignore-case</code></td><td>Búsqueda sin distinguir mayúsculas</td></tr><tr><td><code>fdd</code></td><td><code>fd --list-details</code></td><td>Mostrar detalles de archivo</td></tr><tr><td><code>fde</code></td><td><code>fd --extension</code></td><td>Filtrar por extensión</td></tr><tr><td><code>fdf</code></td><td><code>fd --follow</code></td><td>Seguir enlaces simbólicos</td></tr><tr><td><code>fdh</code></td><td><code>fd --hidden</code></td><td>Incluir archivos ocultos</td></tr><tr><td><code>fdn</code></td><td><code>fd --glob</code></td><td>Coincidir con patrones glob</td></tr><tr><td><code>fdo</code></td><td><code>fd --owner</code></td><td>Filtrar por propietario</td></tr><tr><td><code>fds</code></td><td><code>fd --size</code></td><td>Filtrar por tamaño</td></tr><tr><td><code>fdu</code></td><td><code>fd --exclude</code></td><td>Excluir patrones</td></tr><tr><td><code>fdx</code></td><td><code>fd --exec</code></td><td>Ejecutar un comando por resultado</td></tr></tbody></table><h3 id="comandos-utilitarios" tabindex="-1">Comandos utilitarios <a class="header-anchor" href="#comandos-utilitarios" aria-label="Permalink to &quot;Comandos utilitarios&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>fdv</code></td><td><code>fd --version</code></td><td>Mostrar versión de fd</td></tr></tbody></table>',13)])])}const p=d(i,[["render",s]]);export{m as __pageData,p as default};
